const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

ctx.log("🔍 Gathering comprehensive system telemetry...");

const telemetry = {
  timestamp: Date.now(),
  isoTime: new Date().toISOString(),
  system: {},
  git: {},
  files: {},
  entropy: {}
};

try {
  // CPU and Memory
  const memInfo = fs.readFileSync('/proc/meminfo', 'utf8');
  const memMatch = memInfo.match(/MemTotal:\s+(\d+)/);
  const memFree = memInfo.match(/MemFree:\s+(\d+)/);
  telemetry.system.memory = {
    totalKB: memMatch ? parseInt(memMatch[1]) : null,
    freeKB: memFree ? parseInt(memFree[1]) : null
  };

  // Load average
  const loadavg = fs.readFileSync('/proc/loadavg', 'utf8').split(' ');
  telemetry.system.loadAverage = {
    oneMin: parseFloat(loadavg[0]),
    fiveMin: parseFloat(loadavg[1]),
    fifteenMin: parseFloat(loadavg[2])
  };

  ctx.log("✓ System resources collected");
} catch (e) {
  telemetry.system.error = e.message;
}

try {
  // Git status
  const gitStatus = execSync('git status --porcelain', { encoding: 'utf8', cwd: '/home/bootstrap-v15/bootstrap' });
  const gitBranch = execSync('git branch --show-current', { encoding: 'utf8', cwd: '/home/bootstrap-v15/bootstrap' }).trim();
  const gitLog = execSync('git log --oneline -5', { encoding: 'utf8', cwd: '/home/bootstrap-v15/bootstrap' });

  telemetry.git = {
    branch: gitBranch,
    changes: gitStatus.split('\n').filter(l => l.trim()).length,
    recentCommits: gitLog.split('\n').filter(l => l.trim())
  };

  ctx.log("✓ Git state collected");
} catch (e) {
  telemetry.git.error = e.message;
}

try {
  // File system activity
  const historyDir = '/home/bootstrap-v15/bootstrap/history';
  const sessions = fs.readdirSync(historyDir).filter(f => f.startsWith('session_') && f.endsWith('.json'));

  telemetry.files = {
    totalSessions: sessions.length,
    recentSessions: sessions.sort().slice(-10)
  };

  ctx.log("✓ File system activity collected");
} catch (e) {
  telemetry.files.error = e.message;
}

// Time-based entropy
telemetry.entropy = {
  unixTime: Date.now(),
  hourOfDay: new Date().getHours(),
  dayOfWeek: new Date().getDay(),
  dayOfYear: Math.floor((Date.now() - new Date(new Date().getFullYear(), 0, 0).getTime()) / (1000 * 60 * 60 * 24))
};

// Save telemetry
const outputPath = '/home/bootstrap-v15/bootstrap/telemetry/latest.json';
const outputDir = path.dirname(outputPath);
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}
fs.writeFileSync(outputPath, JSON.stringify(telemetry, null, 2));

ctx.log("✅ Telemetry gathered and saved to " + outputPath);
ctx.updateProgress(100, "Complete");
